BEGIN;

-- Remove system repair annotations from active approval graph nodes.
-- These comments were generated by historical data repair jobs and are not
-- business approval opinions, so they should not appear in approval progress UI.
UPDATE public.approval_nodes
SET comment = NULL,
    updated_at = now()
WHERE comment = 'V0.15 premature summary repair';

UPDATE public.approval_node_assignees
SET comment = NULL
WHERE comment = 'V0.15 premature summary repair';

NOTIFY pgrst, 'reload schema';

COMMIT;
